// src/components/Protected.js
import React from "react";
import { Navigate } from "react-router-dom";

/**
 * ProtectedRoute Component
 * Wraps around a route component to restrict access based on role.
 *
 * Props:
 * - children: The component to render if access is allowed
 * - allowedRoles: Array of roles allowed to access this route
 *
 * Example:
 * <Protected allowedRoles={['admin']}>
 *    <AdminDashboard />
 * </Protected>
 */
const Protected = ({ children, allowedRoles = [] }) => {
  const userRole = localStorage.getItem("role");

  // Not logged in
  if (!userRole) {
    return <Navigate to="/" replace />;
  }

  // Role not allowed
  if (allowedRoles.length && !allowedRoles.includes(userRole)) {
    return (
      <div
        style={{
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
          height: "80vh",
          textAlign: "center",
          flexDirection: "column",
        }}
      >
        <h1 style={{ fontSize: "2rem", color: "#ef4444", marginBottom: "15px" }}>
          Access Denied
        </h1>
        <p style={{ color: "#374151", fontSize: "1rem" }}>
          You do not have permission to view this page.
        </p>
      </div>
    );
  }

  // Access granted
  return children;
};

export default Protected;
